import pika
import json
import time
import sys
from datetime import datetime


class RabbitMQPublisher:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        
    def publish_task(self, task_data):
        if not self.channel:
            self.connect()
            
        message = json.dumps({
            'task_data': task_data,
            'timestamp': datetime.now().isoformat(),
            'status': 'pending'
        })
        
        self.channel.basic_publish(
            exchange='',
            routing_key=self.queue_name,
            body=message,
            properties=pika.BasicProperties(
                delivery_mode=2,
            )
        )
        print(f"[x] Sent task: {task_data}")
        
    def close(self):
        if self.connection:
            self.connection.close()


class RabbitMQConsumer:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
        
    def process_task(self, task_data):
        print(f"[*] Processing task: {task_data}")
        time.sleep(task_data.get('duration', 1))
        print(f"[*] Task completed: {task_data}")
        
    def callback(self, ch, method, properties, body):
        try:
            message = json.loads(body)
            print(f"[x] Received task at {datetime.now().isoformat()}")
            self.process_task(message['task_data'])
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"[!] Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            
    def start_consuming(self):
        if not self.channel:
            self.connect()
            
        print(f"[*] Waiting for tasks in queue '{self.queue_name}'. To exit press CTRL+C")
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.callback
        )
        
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            print("\n[*] Stopping consumer...")
            self.channel.stop_consuming()
        finally:
            self.close()
            
    def close(self):
        if self.connection:
            self.connection.close()


def publish_demo():
    publisher = RabbitMQPublisher()
    publisher.connect()
    
    tasks = [
        {'id': 1, 'name': 'Task 1', 'duration': 2},
        {'id': 2, 'name': 'Task 2', 'duration': 3},
        {'id': 3, 'name': 'Task 3', 'duration': 1},
        {'id': 4, 'name': 'Task 4', 'duration': 4},
        {'id': 5, 'name': 'Task 5', 'duration': 2},
    ]
    
    for task in tasks:
        publisher.publish_task(task)
        time.sleep(0.5)
    
    publisher.close()
    print("[x] All tasks published")


def consume_demo():
    consumer = RabbitMQConsumer()
    consumer.connect()
    consumer.start_consuming()


if __name__ == '__main__':
    if len(sys.argv) > 1:
        if sys.argv[1] == 'publish':
            publish_demo()
        elif sys.argv[1] == 'consume':
            consume_demo()
        else:
            print("Usage: python script.py [publish|consume]")
    else:
        print("Distributed Task Processing System")
